// Returns `el` itself if it matches, otherwise the first matching descendant
function firstMatch(el: HTMLElement, selector: string): HTMLElement | null {
  if (el.matches(selector)) return el;
  return el.querySelector(selector);
}
export function prev(dom: HTMLElement, selector: string): HTMLElement | null {
  
  
  let current: HTMLElement | null = dom;
  while (current) {
    // Try previous siblings (and their subtrees) in reverse
    let sibling = current.previousElementSibling as HTMLElement | null;
    while (sibling) {
      const found = lastMatch(sibling, selector);
      if (found) return found;
      sibling = sibling.previousElementSibling as HTMLElement | null;
    }
    // Climb up to parent
    current = current.parentElement;
  }
  return null;
}

// Returns the LAST matching element in subtree (deepest last descendant first),
// or the element itself if it matches and has no matching descendants
function lastMatch(el: HTMLElement, selector: string): HTMLElement | null {
  // Search descendants in reverse document order
  const all = Array.from(el.querySelectorAll(selector));
  if (all.length > 0) return all[all.length - 1] as HTMLElement;
  if (el.matches(selector)) return el;
  return null;
}
